2000c03glfjF412_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000c03bri84181_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000c03gwkpA64C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000c035lo1FAE0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000c038m8n7990_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233g12000c036ji6E374_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000c03e70226DD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '卫生安静，大气经典。依然是处于第一梯队的酒店，服务一直是标杆，尤其谢谢房务阿姨，', '卫生安静，大气经典。依然是处于第一梯队的酒店，服务一直是标杆，尤其谢谢房务阿姨，还有大堂的高挑姐姐，外籍工作人员，还有Whaley。贴心的现烤曲奇还有伴手礼，太棒啦', '2023-07-23', 5, '[''整体满意度'', ''客房服务'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236812000bq8rr9qFCCC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000bq8ltkhC5D9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000bq8l3gj0152_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '难忘的酒店。虽然家具有点旧，无usd充电插口，但服务人员把自己的借我了，很好。。', '难忘的酒店。虽然家具有点旧，无usd充电插口，但服务人员把自己的借我了，很好。。', '2023-09-24', 5, '[''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235212000c8eh1y5A2F5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000c8eh0w08732_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000c8eh25998B5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店自带一个很漂亮的大园林，房间干净，前台服务热情，下次还会再来。', '酒店自带一个很漂亮的大园林，房间干净，前台服务热情，下次还会再来。', '2023-10-26', 5, '[''整体满意度'', ''卫生状况'', ''前台服务'']', '["[ \"https://dimg0